#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long R; scanf("%lld", &R);
        long long x[3], y[3];
        for (int i=0;i<3;i++) scanf("%lld %lld", &x[i], &y[i]);
        long long limit = R*R;
        long long d01 = (x[0]-x[1])*(x[0]-x[1]) + (y[0]-y[1])*(y[0]-y[1]);
        long long d02 = (x[0]-x[2])*(x[0]-x[2]) + (y[0]-y[2])*(y[0]-y[2]);
        long long d12 = (x[1]-x[2])*(x[1]-x[2]) + (y[1]-y[2])*(y[1]-y[2]);
        if ((d01<=limit && d02<=limit) || (d01<=limit && d12<=limit) || (d02<=limit && d12<=limit))
            printf("yes\n");
        else
            printf("no\n");
    }
    return 0;
}

