import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            long R = Long.parseLong(br.readLine().trim());
            long[] x = new long[3];
            long[] y = new long[3];
            for (int i = 0; i < 3; i++) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                x[i] = Long.parseLong(st.nextToken());
                y[i] = Long.parseLong(st.nextToken());
            }
            long limit = R * R;
            long d01 = sqDist(x[0], y[0], x[1], y[1]);
            long d02 = sqDist(x[0], y[0], x[2], y[2]);
            long d12 = sqDist(x[1], y[1], x[2], y[2]);
            if ((d01 <= limit && d02 <= limit) || (d01 <= limit && d12 <= limit) || (d02 <= limit && d12 <= limit))
                sb.append("yes\n");
            else
                sb.append("no\n");
        }
        System.out.print(sb.toString());
    }
    private static long sqDist(long x1, long y1, long x2, long y2) {
        long dx = x1 - x2;
        long dy = y1 - y2;
        return dx * dx + dy * dy;
    }
}

